// ── SI: symmetric lookup ─────────────────────────────────────
function getRealSI(dyeA, dyeB) {
  if (!dyeA || !dyeB || dyeA === dyeB) return null;
  const a = SI_DATA[dyeA];
  if (a && a[dyeB] !== undefined) return a[dyeB];
  const b = SI_DATA[dyeB];
  if (b && b[dyeA] !== undefined) return b[dyeA];
  return null;
}

// ── SIR: directional — how much A reduces B's staining index ─
function getRealSIR(dyeA, dyeB) {
  if (!dyeA || !dyeB || dyeA === dyeB) return null;
  const a = SIR_DATA[dyeA];
  return (a && a[dyeB] !== undefined) ? a[dyeB] : null;
}

// ── SSM: directional — spillover from A into B's detector ────
function getRealSSM(dyeA, dyeB) {
  if (!dyeA || !dyeB || dyeA === dyeB) return null;
  const a = SSM_DATA[dyeA];
  return (a && a[dyeB] !== undefined) ? a[dyeB] : null;
}

function hasRealSI(dyeA, dyeB)  { return getRealSI(dyeA, dyeB)  !== null; }
function hasRealSIR(dyeA, dyeB) { return getRealSIR(dyeA, dyeB) !== null; }
function hasRealSSM(dyeA, dyeB) { return getRealSSM(dyeA, dyeB) !== null; }

// ── Coverage stats ───────────────────────────────────────────
const SPECTRA_COVERAGE = {
  si_dyes:    148,   si_pairs:  3321,
  sir_dyes:   138,  sir_pairs: 3818,
  ssm_dyes:   146,  ssm_pairs: 6914,
  instrument: 'Cytek Aurora 5L UV/V/B/YG/R',
  source:     'Cytek Cloud Full Spectrum Viewer, May 2026',
};

// ── Exports ──────────────────────────────────────────────────
window.SI_DATA          = SI_DATA;
window.SIR_DATA         = SIR_DATA;
window.SSM_DATA         = SSM_DATA;
window.SPECTRA_COVERAGE = SPECTRA_COVERAGE;
window.getRealSI        = getRealSI;
window.getRealSIR       = getRealSIR;
window.getRealSSM       = getRealSSM;
window.hasRealSI        = hasRealSI;
window.hasRealSIR       = hasRealSIR;
window.hasRealSSM       = hasRealSSM;
